  5→const getApiKey = () => {
  6→  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
  7→    return process.env.API_KEY;
  8→  }
  9→  return null;
 10→};
 11→
 12→const seededScore = (seed: number, offset: number, min = 15, max = 85): number => {
 13→  const raw = ((seed * 37 + offset * 19 + 11) * 17) % 1000;
 14→  return min + Math.round((raw / 1000) * (max - min));
 15→};
 16→
 17→const fallbackSimulation = async (url: string, brandName?: string): Promise<EeatAuditResult> => {
 18→  await new Promise(resolve => setTimeout(resolve, 2800));
 19→
 20→  let hostname: string;
 21→  try { hostname = new URL(url).hostname; } catch { hostname = url; }
 22→  const brand = brandName || hostname;
 23→  const seed = url.length + hostname.length;
 24→
 25→  const experience = seededScore(seed, 1);
 26→  const expertise = seededScore(seed, 2);
 27→  const authoritativeness = seededScore(seed, 3);
 28→  const trustworthiness = seededScore(seed, 4);
 29→  const overall = Math.round((experience + expertise + authoritativeness + trustworthiness) / 4);
 30→
 31→  const findings: EeatAuditResult['findings'] = [
 32→    { category: 'experience', status: experience >= 50 ? 'present' : 'missing', element: 'Temoignages de premiere main', impact: 'high', recommendation: 'Ajouter des etudes de cas detaillees avec des resultats concrets et mesurables.' },
 33→    { category: 'experience', status: experience >= 60 ? 'present' : 'incomplete', element: 'Contenu original (photos, videos)', impact: 'medium', recommendation: 'Integrer des visuels originaux (captures, photos terrain, videos) pour prouver l\'experience.' },
 34→    { category: 'experience', status: experience >= 40 ? 'incomplete' : 'missing', element: 'Details specifiques au metier', impact: 'medium', recommendation: 'Enrichir le contenu avec des termes techniques et des details concrets du secteur.' },
 35→    { category: 'expertise', status: expertise >= 50 ? 'present' : 'missing', element: 'Auteur identifie avec bio', impact: 'high', recommendation: 'Ajouter un bloc auteur avec bio, photo et credentials sur chaque article.' },
 36→    { category: 'expertise', status: expertise >= 60 ? 'present' : 'missing', element: 'Credentials visibles', impact: 'high', recommendation: 'Lister les diplomes, certifications et experiences directement sur la page.' },
 37→    { category: 'expertise', status: expertise >= 40 ? 'incomplete' : 'missing', element: 'Schema.org Person/hasCredential', impact: 'medium', recommendation: 'Implementer le schema JSON-LD Person avec hasCredential et alumniOf.' },
 38→    { category: 'expertise', status: expertise >= 55 ? 'present' : 'incomplete', element: 'Profondeur du contenu', impact: 'medium', recommendation: 'Approfondir les sujets avec des donnees chiffrees, des sources et des exemples.' },
 39→    { category: 'authority', status: authoritativeness >= 50 ? 'present' : 'missing', element: 'Mentions presse', impact: 'high', recommendation: 'Creer un bloc "Ils parlent de nous" avec des citations et liens vers les articles.' },
 40→    { category: 'authority', status: authoritativeness >= 60 ? 'present' : 'missing', element: 'Citations par des pairs', impact: 'medium', recommendation: 'Obtenir des backlinks de sites d\'autorite et des mentions par des experts du secteur.' },
 41→    { category: 'authority', status: authoritativeness >= 40 ? 'incomplete' : 'missing', element: 'Anciennete du domaine', impact: 'low', recommendation: 'Mettre en avant la date de creation du site et l\'historique de l\'entreprise.' },
 42→    { category: 'trust', status: trustworthiness >= 60 ? 'present' : 'present', element: 'HTTPS', impact: 'high', recommendation: 'Le site est accessible en HTTPS (bon signal de confiance).' },
 43→    { category: 'trust', status: trustworthiness >= 50 ? 'present' : 'missing', element: 'Mentions legales', impact: 'high', recommendation: 'Ajouter des mentions legales completes avec raison sociale, SIRET, adresse.' },
 44→    { category: 'trust', status: trustworthiness >= 40 ? 'incomplete' : 'missing', element: 'Contact visible', impact: 'medium', recommendation: 'Afficher clairement email, telephone et adresse sur toutes les pages.' },
 45→    { category: 'trust', status: trustworthiness >= 55 ? 'present' : 'missing', element: 'Avis verifiables', impact: 'high', recommendation: 'Integrer des avis Google/Trustpilot avec Schema.org AggregateRating.' },
 46→    { category: 'trust', status: trustworthiness >= 45 ? 'incomplete' : 'missing', element: 'Politique de confidentialite', impact: 'medium', recommendation: 'Publier une politique de confidentialite detaillee et conforme RGPD.' },
 47→  ];
 48→
 49→  const sortedFindings = [...findings].filter(f => f.status !== 'present').sort((a, b) => {
 50→    const impactOrder = { high: 0, medium: 1, low: 2 };
 51→    return impactOrder[a.impact] - impactOrder[b.impact];
 52→  });
 53→
 54→  const priorityActions: EeatAuditResult['priorityActions'] = sortedFindings.slice(0, 5).map((f, i) => ({
 55→    action: f.recommendation || `Ameliorer : ${f.element}`,
 56→    impact: 100 - i * 15,
 57→    effort: f.impact === 'high' ? 'medium' as const : 'low' as const,
 58→    tool: f.category === 'expertise' ? 'Author Bio Generator' : f.category === 'authority' ? 'Trust Signals Generator' : f.category === 'trust' ? 'Trust Signals Generator' : 'Citation Block Generator',
 59→  }));
 60→
 61→  const summary = overall >= 70
 62→    ? `${brand} presente un bon profil E-E-A-T avec un score de ${overall}/100. Les signaux d'autorite et de confiance sont bien presents. Des ameliorations ciblees sur ${experience < expertise ? 'l\'experience documentee' : 'l\'expertise visible'} permettraient d'atteindre l'excellence.`
 63→    : overall >= 45
 64→      ? `${brand} a un profil E-E-A-T moyen (${overall}/100). Certains signaux sont presents mais des elements cles manquent. Priorite : renforcer les credentials des auteurs, ajouter des preuves sociales et structurer les donnees Schema.org.`
 65→      : `${brand} a un faible score E-E-A-T (${overall}/100). Les moteurs de reponse IA ne trouvent pas suffisamment de signaux d'autorite et de confiance. Une strategie E-E-A-T complete est necessaire : bios auteurs, certifications, avis, mentions legales.`;
 66→
 67→  return {
 68→    url,
 69→    scores: { overall, experience, expertise, authoritativeness, trustworthiness },
 70→    findings,
 71→    priorityActions,
 72→    summary,
 73→  };
 74→};
 75→
 76→const buildResponseSchema = (): Schema => {
 77→  const findingSchema: Schema = {
 78→    type: Type.OBJECT,
 79→    properties: {
 80→      category: { type: Type.STRING, description: "experience | expertise | authority | trust" },
 81→      status: { type: Type.STRING, description: "present | missing | incomplete" },
 82→      element: { type: Type.STRING, description: "Element E-E-A-T evalue" },
 83→      impact: { type: Type.STRING, description: "high | medium | low" },
 84→      recommendation: { type: Type.STRING, description: "Recommandation actionable" },
 85→    },
 86→    required: ["category", "status", "element", "impact"],
 87→  };
 88→
 89→  const actionSchema: Schema = {
 90→    type: Type.OBJECT,
 91→    properties: {
 92→      action: { type: Type.STRING },
 93→      impact: { type: Type.NUMBER },
 94→      effort: { type: Type.STRING, description: "low | medium | high" },
 95→      tool: { type: Type.STRING, description: "Outil E-E-A-T recommande" },
 96→    },
 97→    required: ["action", "impact", "effort", "tool"],
 98→  };
 99→
100→  return {
101→    type: Type.OBJECT,
102→    properties: {
103→      scores: {
104→        type: Type.OBJECT,
105→        properties: {
106→          overall: { type: Type.NUMBER },
107→          experience: { type: Type.NUMBER },
108→          expertise: { type: Type.NUMBER },
109→          authoritativeness: { type: Type.NUMBER },
110→          trustworthiness: { type: Type.NUMBER },
111→        },
112→        required: ["overall", "experience", "expertise", "authoritativeness", "trustworthiness"],
113→      },
114→      findings: { type: Type.ARRAY, items: findingSchema },
115→      priorityActions: { type: Type.ARRAY, items: actionSchema },
116→      summary: { type: Type.STRING },
117→    },
118→    required: ["scores", "findings", "priorityActions", "summary"],
119→  };
120→};
