122→export const auditEeat = async (url: string, brandName?: string): Promise<EeatAuditResult> => {
123→  const apiKey = getApiKey();
124→  if (!apiKey) {
125→    console.warn("API_KEY not found, using simulation.");
126→    return fallbackSimulation(url, brandName);
127→  }
128→
129→  try {
130→    const ai = new GoogleGenAI({ apiKey });
131→
132→    const prompt = `${PROMPT_EEAT_AUDIT}\n\nURL: ${url}\n${brandName ? `MARQUE: ${brandName}` : ''}\n\nAnalyse la page et genere l'audit E-E-A-T complet.`;
133→
134→    const response = await ai.models.generateContent({
135→      model: 'gemini-2.5-flash',
136→      contents: prompt,
137→      config: {
138→        responseMimeType: 'application/json',
139→        responseSchema: buildResponseSchema(),
140→        temperature: 0.3,
141→      }
142→    });
143→
144→    let output = response.text;
145→    if (!output) throw new Error("Empty response");
146→    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
147→
148→    const parsed = JSON.parse(output);
149→    return { url, ...parsed };
150→  } catch (error) {
151→    console.error("E-E-A-T Audit failed:", error);
152→    return fallbackSimulation(url, brandName);
153→  }
154→};
