 87→// Animated number hook for smooth credit transitions
 88→const useAnimatedNumber = (value: number, duration = 600) => {
 89→  const [display, setDisplay] = useState(value);
 90→  const prevValue = useRef(value);
 91→  useEffect(() => {
 92→    if (prevValue.current === value) return;
 93→    const start = prevValue.current;
 94→    const diff = value - start;
 95→    const startTime = performance.now();
 96→    const animate = (now: number) => {
 97→      const progress = Math.min((now - startTime) / duration, 1);
 98→      const eased = 1 - Math.pow(1 - progress, 3);
 99→      setDisplay(Math.round(start + diff * eased));
100→      if (progress < 1) requestAnimationFrame(animate);
101→    };
102→    requestAnimationFrame(animate);
103→    prevValue.current = value;
104→  }, [value, duration]);
105→  return display;
106→};
