248→  const [isProfileOpen, setIsProfileOpen] = useState(false);
249→  const profileRef = useRef<HTMLDivElement>(null);
250→  useEffect(() => {
251→    const handleClickOutside = (e: MouseEvent) => {
252→      if (profileRef.current && !profileRef.current.contains(e.target as Node)) setIsProfileOpen(false);
253→    };
254→    if (isProfileOpen) document.addEventListener('mousedown', handleClickOutside);
255→    return () => document.removeEventListener('mousedown', handleClickOutside);
256→  }, [isProfileOpen]);
257→
258→  // ── Page transition ──
