263→  const [showBackToTop, setShowBackToTop] = useState(false);
264→  const lastScrollY = useRef(0);
265→  useEffect(() => {
266→    const handleScroll = () => {
267→      const currentY = window.scrollY;
268→      if (currentY < 60) {
269→        setNavbarVisible(true);
270→      } else if (currentY > lastScrollY.current + 10) {
271→        setNavbarVisible(false);
272→      } else if (currentY < lastScrollY.current - 10) {
273→        setNavbarVisible(true);
274→      }
275→      lastScrollY.current = currentY;
276→      // Back to top visibility
277→      setShowBackToTop(currentY > 400);
