411→
412→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
413→    const now = new Date();
414→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
415→
416→    // 1. Identifier la date de création (première analyse) de chaque domaine
417→    const projectCreationDates = new Map<string, Date>();
418→    
419→    history.forEach(h => {
420→        let hostname;
421→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
422→        
423→        const analysisDate = new Date(h.timestamp);
424→        
425→        if (!projectCreationDates.has(hostname)) {
426→            projectCreationDates.set(hostname, analysisDate);
427→        } else {
428→            // On garde la date la plus ancienne trouvée pour ce domaine
429→            if (analysisDate < projectCreationDates.get(hostname)!) {
430→                projectCreationDates.set(hostname, analysisDate);
431→            }
432→        }
433→    });
434→
435→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
436→    let count = 0;
437→    projectCreationDates.forEach((creationDate) => {
438→        if (creationDate >= billingCycleStart) {
439→            count++;
440→        }
441→    });
442→    
443→    return count;
