              {sentimentScore > 20 ? <ThumbsUp size={16} className="text-emerald-400" /> : sentimentScore > -10 ? <Minus size={16} className="text-amber-400" /> : <ThumbsDown size={16} className="text-red-400" />}
            </div>
          </div>
          <div className={`text-3xl font-bold ${sentimentColor}`}>{sentimentLabel}</div>
          <div className="flex gap-1 mt-2">
            <div className="bg-emerald-500/30 rounded-full h-1.5 transition-all" style={{ width: `${result.overallSentiment.positive}%` }} />
            <div className="bg-gray-500/30 rounded-full h-1.5 transition-all" style={{ width: `${result.overallSentiment.neutral}%` }} />
            <div className="bg-red-500/30 rounded-full h-1.5 transition-all" style={{ width: `${result.overallSentiment.negative}%` }} />
          </div>
        </div>

        {/* Trend */}
        <div className="ninja-card p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xs text-gray-500 font-medium uppercase tracking-wider">Tendance</span>
            <div className={`p-2 rounded-xl ${result.trend >= 0 ? 'bg-emerald-500/10' : 'bg-red-500/10'}`}>
              {result.trend >= 0 ? <TrendingUp size={16} className="text-emerald-400" /> : <TrendingDown size={16} className="text-red-400" />}
            </div>
          </div>
          <div className={`text-3xl font-bold ${result.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
            {result.trend >= 0 ? '+' : ''}{result.trend}%
          </div>
          <div className="text-xs text-gray-500 mt-1">Evolution sur la periode</div>
        </div>
      </div>

      {/* ── Charts Row ── */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
        {/* Area Chart - Citations over time */}
        <div className="ninja-card p-6 lg:col-span-2">
          <h3 className="text-lg font-bold text-white mb-1">Citations dans le temps</h3>
          <p className="text-xs text-gray-500 mb-6">Nombre de citations par jour et par moteur IA</p>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={result.timeSeries} margin={{ top: 5, right: 10, left: -10, bottom: 5 }}>
                <defs>
                  <linearGradient id="colorChatgpt" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
                  </linearGradient>
                  <linearGradient id="colorClaude" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#a855f7" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#a855f7" stopOpacity={0} />
                  </linearGradient>
                  <linearGradient id="colorPerplexity" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#3b82f6" stopOpacity={0} />
                  </linearGradient>
                  <linearGradient id="colorGemini" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#f59e0b" stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
                <XAxis
                  dataKey="date"
                  tick={{ fill: '#6b7280', fontSize: 11 }}
                  axisLine={{ stroke: 'rgba(255,255,255,0.06)' }}
                  tickLine={false}
                  tickFormatter={(v) => {
                    const d = new Date(v);
                    return `${d.getDate()}/${d.getMonth() + 1}`;
                  }}
                />
                <YAxis
                  tick={{ fill: '#6b7280', fontSize: 11 }}
                  axisLine={false}
                  tickLine={false}
                  allowDecimals={false}
                />
                <Tooltip content={<CustomTooltip />} />
                <Legend
                  wrapperStyle={{ fontSize: '12px', paddingTop: '12px' }}
                  iconType="circle"
                  iconSize={8}
                />
                <Area type="monotone" dataKey="chatgpt" name="ChatGPT" stroke="#10b981" fill="url(#colorChatgpt)" strokeWidth={2} />
                <Area type="monotone" dataKey="claude" name="Claude" stroke="#a855f7" fill="url(#colorClaude)" strokeWidth={2} />
                <Area type="monotone" dataKey="perplexity" name="Perplexity" stroke="#3b82f6" fill="url(#colorPerplexity)" strokeWidth={2} />
                <Area type="monotone" dataKey="gemini" name="Gemini" stroke="#f59e0b" fill="url(#colorGemini)" strokeWidth={2} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Horizontal Bar Chart - Distribution by engine */}
        <div className="ninja-card p-6">
          <h3 className="text-lg font-bold text-white mb-1">Distribution par moteur</h3>
          <p className="text-xs text-gray-500 mb-6">Repartition des citations</p>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                layout="vertical"
                data={result.engineResults.map(e => ({
                  engine: e.engine,
                  citations: e.totalCitations,
                  sov: e.shareOfVoice,
                }))}
                margin={{ top: 5, right: 10, left: 10, bottom: 5 }}
              >
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" horizontal={false} />
                <XAxis type="number" tick={{ fill: '#6b7280', fontSize: 11 }} axisLine={false} tickLine={false} />
                <YAxis type="category" dataKey="engine" tick={{ fill: '#9ca3af', fontSize: 12, fontWeight: 500 }} axisLine={false} tickLine={false} width={80} />
                <Tooltip content={<CustomTooltip />} />
                <Bar dataKey="citations" name="Citations" radius={[0, 6, 6, 0]} barSize={24}>
                  {result.engineResults.map((entry) => (
                    <Cell key={entry.engine} fill={ENGINE_COLORS[entry.engine]} fillOpacity={0.8} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* ── Engine Detail Cards ── */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {result.engineResults.map((engine) => (
          <div key={engine.engine} className="ninja-card p-5">
            <div className="flex items-center justify-between mb-4">
              <span className={`text-sm font-bold px-2.5 py-1 rounded-lg border ${ENGINE_BG[engine.engine]}`}>
                {engine.engine}
              </span>
              <span className={`text-xs font-medium flex items-center gap-1 ${engine.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                {engine.trend >= 0 ? <TrendingUp size={10} /> : <TrendingDown size={10} />}
                {engine.trend >= 0 ? '+' : ''}{engine.trend}%
              </span>
            </div>
            <div className="space-y-3">
              <div className="flex justify-between items-center">
                <span className="text-xs text-gray-500">Citations</span>
                <span className="text-sm font-bold text-white">{engine.totalCitations}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-xs text-gray-500">Part de voix</span>
                <span className="text-sm font-bold text-white">{engine.shareOfVoice}%</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-xs text-gray-500">Position moy.</span>
                <span className="text-sm font-bold text-white">#{engine.avgPosition}</span>
              </div>
              <div className="pt-2 border-t border-white/[0.06]">
                <span className="text-xs text-gray-500 block mb-2">Sentiment</span>
                <div className="flex gap-1">
                  <div className="bg-emerald-500/30 rounded-full h-1.5" style={{ width: `${engine.sentiment.positive}%` }} />
                  <div className="bg-gray-500/30 rounded-full h-1.5" style={{ width: `${engine.sentiment.neutral}%` }} />
                  <div className="bg-red-500/30 rounded-full h-1.5" style={{ width: `${engine.sentiment.negative}%` }} />
                </div>
                <div className="flex justify-between mt-1.5">
                  <span className="text-[10px] text-emerald-400">{engine.sentiment.positive}%</span>
                  <span className="text-[10px] text-gray-500">{engine.sentiment.neutral}%</span>
                  <span className="text-[10px] text-red-400">{engine.sentiment.negative}%</span>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* ── Citations Table ── */}
      <div className="ninja-card p-6 mb-8">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h3 className="text-lg font-bold text-white">Citations recentes</h3>
            <p className="text-xs text-gray-500 mt-0.5">{result.citations.length} citations detectees</p>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-white/[0.06]">
                <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Moteur</th>
                <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Requete</th>
                <th className="text-center text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Position</th>
                <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Date</th>
                <th className="text-center text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Sentiment</th>
                <th className="text-center text-xs font-medium text-gray-500 uppercase tracking-wider pb-3">Confiance</th>
              </tr>
            </thead>
            <tbody>
              {result.citations.slice(0, 15).map((citation) => {
                const sentCfg = SENTIMENT_CONFIG[citation.sentiment];
                const SentIcon = sentCfg.icon;
                return (
                  <tr key={citation.id} className="border-b border-white/[0.03] hover:bg-white/[0.02] transition-colors">
                    <td className="py-3.5 pr-4">
                      <span className={`text-xs font-medium px-2 py-1 rounded-md border ${ENGINE_BG[citation.engine]}`}>
                        {citation.engine}
                      </span>
                    </td>
                    <td className="py-3.5 pr-4">
                      <div className="max-w-xs">
                        <p className="text-sm text-gray-200 truncate">{citation.query}</p>
                        <p className="text-xs text-gray-600 truncate mt-0.5">{citation.snippet}</p>
                      </div>
                    </td>
                    <td className="py-3.5 pr-4 text-center">
                      <span className={`text-sm font-bold ${citation.position <= 2 ? 'text-emerald-400' : citation.position <= 4 ? 'text-amber-400' : 'text-gray-400'}`}>
                        #{citation.position}
                      </span>
                    </td>
                    <td className="py-3.5 pr-4">
                      <span className="text-xs text-gray-400">{new Date(citation.date).toLocaleDateString('fr-FR')}</span>
                    </td>
                    <td className="py-3.5 pr-4 text-center">
                      <span className={`inline-flex items-center gap-1 text-xs px-2 py-1 rounded-md ${sentCfg.bg} ${sentCfg.color}`}>
                        <SentIcon size={10} />
                        {sentCfg.label}
                      </span>
                    </td>
                    <td className="py-3.5 text-center">
                      <span className="text-xs text-gray-400">{citation.confidence}%</span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* ── Competitor Comparison ── */}
      <div className="ninja-card p-6 mb-8">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h3 className="text-lg font-bold text-white">Comparaison concurrentielle</h3>
            <p className="text-xs text-gray-500 mt-0.5">Votre marque vs les concurrents detectes</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
          {/* Your brand card */}
          <div className="p-4 rounded-xl bg-gradient-to-br from-purple-500/10 to-violet-600/10 border border-purple-500/20">
            <div className="flex items-center gap-2 mb-3">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center">
                <Sparkles size={14} className="text-white" />
              </div>
              <div>
                <p className="text-sm font-bold text-white truncate">{result.brandName}</p>
